/*!
 * Hexo Theme Suka | local-search.js
 * Local override: live search, CJK-friendly matching, and stable result rendering.
 */
(function () {
    var searchKeyword = '';

    window.getParameterByName = function (name) {
        name = name.replace(/[\[]/, '\\[').replace(/[\]]/, '\\]');
        var regex = new RegExp('[\\?&]' + name + '=([^&#]*)');
        var results = regex.exec(window.location.search);
        return results == null ? '' : decodeURIComponent(results[1].replace(/\+/g, ' '));
    };

    window.searchEscape = function (keyword) {
        var htmlEntityMap = {
            '&': '&amp;',
            '<': '&lt;',
            '>': '&gt;',
            '"': '&quot;',
            '\'': '&#39;',
            '/': '&#x2F;'
        };

        return String(keyword || '').replace(/[&<>"'/]/g, function (i) {
            return htmlEntityMap[i];
        });
    };

    function normalizeText(text) {
        return String(text || '')
            .normalize('NFKC')
            .toLowerCase()
            .replace(/[\u3000\s]+/g, ' ')
            .trim();
    }

    function escapeRegExp(text) {
        return String(text || '').replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
    }

    function parseKeywords(key) {
        return normalizeText(key)
            .split(/[\s\-+]+/)
            .filter(Boolean);
    }

    function highlight(text, keywords) {
        var source = window.searchEscape(text);
        if (!keywords.length) return source;

        var pattern = keywords
            .slice()
            .sort(function (a, b) { return b.length - a.length; })
            .map(escapeRegExp)
            .join('|');

        if (!pattern) return source;
        return source.replace(new RegExp('(' + pattern + ')', 'giu'), '<strong><mark>$1</mark></strong>');
    }

    function snippet(content, keywords) {
        var source = String(content || '').replace(/\s+/g, ' ').trim();
        if (!source) return '';

        var normalized = normalizeText(source);
        var hitIndex = -1;
        var hitKeyword = '';

        keywords.forEach(function (keyword) {
            if (hitIndex >= 0) return;
            var index = normalized.indexOf(keyword);
            if (index >= 0) {
                hitIndex = index;
                hitKeyword = keyword;
            }
        });

        if (hitIndex < 0) return source.slice(0, 90);

        var start = Math.max(0, hitIndex - 45);
        var end = Math.min(source.length, hitIndex + hitKeyword.length + 70);
        return (start > 0 ? '...' : '') + source.slice(start, end) + (end < source.length ? '...' : '');
    }

    window.searchFunc = function (searchFilePath, noResultText) {
        'use strict';

        fetch(searchFilePath).then(function (res) {
            return res.json();
        }).then(function (datas) {
            var $input = document.getElementById('search-field');
            var $form = $input && $input.closest('form');
            var $resultContent = document.getElementById('search-output');
            var $resultNum = document.getElementById('search-result-num');
            var $resultInfo = document.getElementById('search-result-info');
            var timer = null;

            if (!$input || !$resultContent || !$resultNum || !$resultInfo) return;

            function renderNoResult(key) {
                var escaped = window.searchEscape(key);
                $resultInfo.style.display = 'none';
                $resultContent.innerHTML = noResultText.replace(/__QUERY__/g, escaped);
            }

            function search(key) {
                var keywords = parseKeywords(key);
                searchKeyword = key;
                window.searchKeyword = keywords;
                $resultContent.innerHTML = '';
                $resultNum.textContent = '';

                if (!keywords.length) {
                    $resultInfo.style.display = 'none';
                    return;
                }

                var results = [];

                datas.forEach(function (data) {
                    if (typeof data.title === 'undefined' || typeof data.content === 'undefined') return;

                    var title = normalizeText(data.title);
                    var content = normalizeText(data.content.replace(/<[^>]+>/g, ''));
                    var tags = Array.isArray(data.tags) ? normalizeText(data.tags.join(' ')) : '';
                    var categories = Array.isArray(data.categories) ? normalizeText(data.categories.join(' ')) : '';
                    var haystack = [title, content, tags, categories].join(' ');
                    var isMatch = keywords.every(function (keyword) {
                        return haystack.indexOf(keyword) >= 0;
                    });

                    if (!isMatch) return;

                    var weight = 0;
                    keywords.forEach(function (keyword) {
                        if (title.indexOf(keyword) >= 0) weight += 4;
                        if (tags.indexOf(keyword) >= 0) weight += 2;
                        if (categories.indexOf(keyword) >= 0) weight += 2;
                        if (content.indexOf(keyword) >= 0) weight += 1;
                    });

                    results.push({
                        data: data,
                        weight: weight
                    });
                });

                results.sort(function (a, b) {
                    return b.weight - a.weight;
                });

                if (!results.length) {
                    renderNoResult(key);
                    return;
                }

                $resultNum.textContent = results.length;
                $resultInfo.style.display = 'block';
                $resultContent.innerHTML = results.map(function (item) {
                    var data = item.data;
                    var date = data.date ? new Date(data.date).toLocaleDateString() : '';
                    var summary = snippet(data.content, keywords);

                    return '<div class="tile"><div class="tile-content">' +
                        '<a href="' + window.searchEscape(data.url) + '">' +
                        '<p class="tile-title search-result-title">' + highlight(data.title, keywords) + '</p>' +
                        '</a>' +
                        '<p class="text-gray search-result-summary">' +
                        '<span class="saerch-result-date">' + window.searchEscape(date) + '</span>' +
                        highlight(summary, keywords) +
                        '</p>' +
                        '</div></div>';
                }).join('');
            }

            function syncUrl(key) {
                var url = new URL(window.location.href);
                if (key.trim()) url.searchParams.set('s', key.trim());
                else url.searchParams.delete('s');
                window.history.replaceState({}, '', url);
            }

            function scheduleSearch(key) {
                clearTimeout(timer);
                timer = setTimeout(function () {
                    syncUrl(key);
                    search(key);
                }, 150);
            }

            searchKeyword = window.getParameterByName('s');
            $input.value = searchKeyword;
            if (searchKeyword) search(searchKeyword);

            $input.addEventListener('input', function () {
                scheduleSearch($input.value || '');
            });

            if ($form) {
                $form.addEventListener('submit', function (event) {
                    event.preventDefault();
                    syncUrl($input.value || '');
                    search($input.value || '');
                });
            }
        }).catch(function () {
            var $resultContent = document.getElementById('search-output');
            if ($resultContent) {
                $resultContent.innerHTML = '<div class="search-noresult">搜索索引加载失败，请稍后重试。</div>';
            }
        });
    };
})();
